import{_ as e,o as a,c as i,ag as t}from"./chunks/framework.Dn0B0GT3.js";const k=JSON.parse('{"title":"Basic Usage","description":"Complete reference for all ShellPort CLI options with examples","frontmatter":{"title":"Basic Usage","description":"Complete reference for all ShellPort CLI options with examples"},"headers":[],"relativePath":"guides/basic-usage.md","filePath":"guides/basic-usage.md"}'),l={name:"guides/basic-usage.md"};function n(r,s,p,h,o,d){return a(),i("div",null,[...s[0]||(s[0]=[t('<h1 id="basic-usage" tabindex="-1">Basic Usage <a class="header-anchor" href="#basic-usage" aria-label="Permalink to &quot;Basic Usage&quot;">​</a></h1><p>This page documents all command-line options available when running the ShellPort server.</p><h2 id="quick-reference" tabindex="-1">Quick Reference <a class="header-anchor" href="#quick-reference" aria-label="Permalink to &quot;Quick Reference&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                    # Full security — encrypted + TOTP 2FA (default)</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8080</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # Custom port</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --secret</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> KEY</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # Fixed encryption secret</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-totp</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # Encrypted only, skip TOTP</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-secret</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # TOTP only (no encryption)</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-secret</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-totp</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # Plaintext mode</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --totp-reset</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # Regenerate TOTP pairing secret</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-approval</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # Disable connection approval</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dev</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # Allow localhost origin bypass</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tailscale</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Expose via Tailscale serve</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tailscale</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> funnel</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # Expose via Tailscale funnel</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --quiet</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # Suppress non-essential output</span></span></code></pre></div><h2 id="all-cli-options" tabindex="-1">All CLI Options <a class="header-anchor" href="#all-cli-options" aria-label="Permalink to &quot;All CLI Options&quot;">​</a></h2><h3 id="port-p" tabindex="-1"><code>--port</code>, <code>-p</code> <a class="header-anchor" href="#port-p" aria-label="Permalink to &quot;`--port`, `-p`&quot;">​</a></h3><p><strong>Description:</strong> Server port to listen on.</p><p><strong>Default:</strong> <code>7681</code></p><p><strong>Example:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8080</span></span></code></pre></div><hr><h3 id="secret-s" tabindex="-1"><code>--secret</code>, <code>-s</code> <a class="header-anchor" href="#secret-s" aria-label="Permalink to &quot;`--secret`, `-s`&quot;">​</a></h3><p><strong>Description:</strong> Fixed encryption secret. When omitted, a random 128-bit secret is auto-generated per session.</p><p><strong>Default:</strong> <em>(auto-generated)</em></p><p><strong>Example:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --secret</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-secret-key</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>It&#39;s recommended to let ShellPort auto-generate the secret. The secret is passed via URL fragment (<code>#secret</code>) and is never sent to the server.</p></div><hr><h3 id="no-secret" tabindex="-1"><code>--no-secret</code> <a class="header-anchor" href="#no-secret" aria-label="Permalink to &quot;`--no-secret`&quot;">​</a></h3><p><strong>Description:</strong> Disable encryption entirely (plaintext mode). Use this when you don&#39;t need E2E encryption and are running over a VPN like Tailscale.</p><p><strong>Default:</strong> <em>(off — encryption enabled)</em></p><p><strong>Example:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-secret</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Without encryption, all terminal data is transmitted in plaintext. Only use this on trusted networks.</p></div><hr><h3 id="no-totp" tabindex="-1"><code>--no-totp</code> <a class="header-anchor" href="#no-totp" aria-label="Permalink to &quot;`--no-totp`&quot;">​</a></h3><p><strong>Description:</strong> Disable TOTP two-factor authentication. The connection will still be encrypted if no secret is set.</p><p><strong>Default:</strong> <em>(off — TOTP enabled)</em></p><p><strong>Example:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-totp</span></span></code></pre></div><hr><h3 id="totp-reset" tabindex="-1"><code>--totp-reset</code> <a class="header-anchor" href="#totp-reset" aria-label="Permalink to &quot;`--totp-reset`&quot;">​</a></h3><p><strong>Description:</strong> Regenerate the TOTP pairing secret. Use this if you need to re-pair your authenticator app.</p><p><strong>Default:</strong> <em>(off)</em></p><p><strong>Example:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --totp-reset</span></span></code></pre></div><p>This will delete the existing TOTP secret from <code>~/.shellport-totp-secret</code> and generate a new QR code on next startup.</p><hr><h3 id="no-approval" tabindex="-1"><code>--no-approval</code> <a class="header-anchor" href="#no-approval" aria-label="Permalink to &quot;`--no-approval`&quot;">​</a></h3><p><strong>Description:</strong> Disable interactive connection approval prompts. The server host won&#39;t be asked to approve each connection.</p><p><strong>Default:</strong> <em>(off — approval required)</em></p><p><strong>Example:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-approval</span></span></code></pre></div><hr><h3 id="dev-allow-localhost" tabindex="-1"><code>--dev</code>, <code>--allow-localhost</code> <a class="header-anchor" href="#dev-allow-localhost" aria-label="Permalink to &quot;`--dev`, `--allow-localhost`&quot;">​</a></h3><p><strong>Description:</strong> Allow localhost origin bypass for WebSocket connections. This relaxes origin validation for local development.</p><p><strong>Default:</strong> <em>(off — strict origin enforcement)</em></p><p><strong>Example:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dev</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Never use this flag in production or on exposed servers.</p></div><hr><h3 id="tailscale" tabindex="-1"><code>--tailscale</code> <a class="header-anchor" href="#tailscale" aria-label="Permalink to &quot;`--tailscale`&quot;">​</a></h3><p><strong>Description:</strong> Enable Tailscale integration. Accepts <code>serve</code> or <code>funnel</code> mode.</p><p><strong>Default:</strong> <em>(disabled)</em></p><p><strong>Values:</strong></p><ul><li><code>serve</code> — Expose the server through your Tailscale network</li><li><code>funnel</code> — Expose the server to the public internet via Tailscale Funnel</li></ul><p><strong>Example:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Expose via Tailscale network</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tailscale</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Expose to public internet</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tailscale</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> funnel</span></span></code></pre></div><p>See the <a href="/shellport/shellport/guides/tailscale.html">Tailscale Integration</a> guide for full details.</p><hr><h3 id="quiet-q" tabindex="-1"><code>--quiet</code>, <code>-q</code> <a class="header-anchor" href="#quiet-q" aria-label="Permalink to &quot;`--quiet`, `-q`&quot;">​</a></h3><p><strong>Description:</strong> Suppress non-essential output such as the TOTP secret loading message.</p><p><strong>Default:</strong> <em>(off — all output shown)</em></p><p><strong>Example:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --quiet</span></span></code></pre></div><hr><h2 id="environment-variables" tabindex="-1">Environment Variables <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;Environment Variables&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>SHELLPORT_SECRET</code></td><td>Fixed encryption key (avoids exposing in <code>ps</code>)</td></tr><tr><td><code>SHELLPORT_APPROVAL_MODE</code></td><td>Set to <code>disabled</code> to skip approval prompts</td></tr></tbody></table><hr><h2 id="security-modes" tabindex="-1">Security Modes <a class="header-anchor" href="#security-modes" aria-label="Permalink to &quot;Security Modes&quot;">​</a></h2><p>By combining flags, you can choose between four security modes:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Flags</th><th>Encryption</th><th>TOTP</th><th>Use Case</th></tr></thead><tbody><tr><td><strong>Full security</strong></td><td><em>(none)</em></td><td>✅ AES-256-GCM</td><td>✅</td><td>Default — maximum security</td></tr><tr><td><strong>Encrypted only</strong></td><td><code>--no-totp</code></td><td>✅ AES-256-GCM</td><td>❌</td><td>Trusted environment</td></tr><tr><td><strong>TOTP only</strong></td><td><code>--no-secret</code></td><td>❌</td><td>✅</td><td>Remote via VPN/Tailscale</td></tr><tr><td><strong>Plaintext</strong></td><td><code>--no-secret --no-totp</code></td><td>❌</td><td>❌</td><td>Localhost dev only</td></tr></tbody></table><p>See the <a href="/shellport/shellport/guides/security.html">Security</a> guide for full details on each mode.</p><hr><h2 id="common-usage-patterns" tabindex="-1">Common Usage Patterns <a class="header-anchor" href="#common-usage-patterns" aria-label="Permalink to &quot;Common Usage Patterns&quot;">​</a></h2><h3 id="default-secure-server" tabindex="-1">Default secure server <a class="header-anchor" href="#default-secure-server" aria-label="Permalink to &quot;Default secure server&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span></span></code></pre></div><h3 id="tailscale-public-access" tabindex="-1">Tailscale public access <a class="header-anchor" href="#tailscale-public-access" aria-label="Permalink to &quot;Tailscale public access&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tailscale</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> funnel</span></span></code></pre></div><h3 id="development-with-relaxed-security" tabindex="-1">Development with relaxed security <a class="header-anchor" href="#development-with-relaxed-security" aria-label="Permalink to &quot;Development with relaxed security&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-totp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-approval</span></span></code></pre></div><h3 id="single-flag-tailscale-serve" tabindex="-1">Single-flag Tailscale serve <a class="header-anchor" href="#single-flag-tailscale-serve" aria-label="Permalink to &quot;Single-flag Tailscale serve&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tailscale</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span></span></code></pre></div>',83)])])}const g=e(l,[["render",n]]);export{k as __pageData,g as default};
